		   pci_name(pci));
	if (use_vga_switcheroo(chip)) {
		snd_printk(KERN_INFO SFX "Delaying initialization\n");
		chip->disabled = true;
		goto ok;
	}
	kfree(chip);
	pci_disable_device(pci);

